void deposit_worker(BankV2& bank, TransactionLog& log,
                    const std::string& account_id, int num_transactions) {
    std::mt19937 rng(std::hash<std::thread::id>{}(std::this_thread::get_id()));
    std::uniform_real_distribution<double> amount_dist(1.0, 100.0);

    for (int i = 0; i < num_transactions; ++i) {
        double amount = std::round(amount_dist(rng) * 100.0) / 100.0;
        try {
            bank.deposit(account_id, amount);
            log.log("DEPOSIT " + account_id + " $" + std::to_string(amount));
        } catch (const std::exception& e) {
            log.log("DEPOSIT FAILED " + account_id + ": " + e.what());
        }
        std::this_thread::sleep_for(std::chrono::microseconds(100));
    }
}

