void transfer_worker(BankV2& bank, TransactionLog& log,
                     const std::vector<std::string>& account_ids, int num_transactions) {
    std::mt19937 rng(std::hash<std::thread::id>{}(std::this_thread::get_id()) ^ 0xCAFEBABE);
    std::uniform_real_distribution<double> amount_dist(1.0, 200.0);
    std::uniform_int_distribution<size_t> account_dist(0, account_ids.size() - 1);

    for (int i = 0; i < num_transactions; ++i) {
        size_t from_idx = account_dist(rng);
        size_t to_idx = account_dist(rng);
        while (to_idx == from_idx) {
            to_idx = account_dist(rng);
        }

        double amount = std::round(amount_dist(rng) * 100.0) / 100.0;
        const std::string& from_id = account_ids[from_idx];
        const std::string& to_id = account_ids[to_idx];

        try {
            bool success = bank.transfer(from_id, to_id, amount);
            if (success) {
                log.log("TRANSFER " + from_id + " -> " + to_id + " $" + std::to_string(amount));
            } else {
                log.log("TRANSFER DECLINED " + from_id + " -> " + to_id + " $" + std::to_string(amount) + " (insufficient funds)");
            }
        } catch (const std::exception& e) {
            log.log("TRANSFER FAILED " + from_id + " -> " + to_id + ": " + e.what());
        }
        std::this_thread::sleep_for(std::chrono::microseconds(200));
    }
}

